create extension if not exists pgcrypto;
create table users_profile (id uuid primary key default gen_random_uuid(), user_id uuid not null, email text not null, full_name text, role text not null default 'admin', created_at timestamptz default now(), updated_at timestamptz default now());
create table provider_credentials (id uuid primary key default gen_random_uuid(), provider_name text not null, credential_label text not null, encrypted_value text not null, status text default 'untested', created_by uuid, created_at timestamptz default now(), updated_at timestamptz default now(), last_tested_at timestamptz);
create table ai_sessions (id uuid primary key default gen_random_uuid(), session_name text not null, provider text not null default 'runpod', model_id text not null, pod_id text, endpoint_url text, status text not null default 'pending', gpu_type text, gpu_count int not null default 8, estimated_hourly_cost numeric, max_hours int not null default 4, started_at timestamptz, stopped_at timestamptz, auto_stop_at timestamptz, created_by uuid, created_at timestamptz default now(), updated_at timestamptz default now());
create table model_runtimes (id uuid primary key default gen_random_uuid(), session_id uuid references ai_sessions(id) on delete cascade, model_id text not null, serving_engine text not null default 'vllm', status text not null default 'stopped', health_url text, api_base_url text, context_length int default 32768, quantization text default 'fp8', tensor_parallel_size int default 8, pipeline_parallel_size int default 1, last_health_check_at timestamptz, created_at timestamptz default now(), updated_at timestamptz default now());
create table ai_tasks (id uuid primary key default gen_random_uuid(), title text not null, description text not null, task_type text, priority text default 'normal', status text default 'queued', project_id uuid, repo_id uuid, session_id uuid references ai_sessions(id), allowed_tools text[] default array['chat_only'], risk_level text default 'low', requires_approval boolean default false, input_payload jsonb default '{}'::jsonb, output_summary text, output_payload jsonb, error_message text, created_by uuid, assigned_to_model text, started_at timestamptz, completed_at timestamptz, created_at timestamptz default now(), updated_at timestamptz default now());
create table ai_task_logs (id uuid primary key default gen_random_uuid(), task_id uuid references ai_tasks(id) on delete cascade, session_id uuid references ai_sessions(id), log_level text default 'info', message text not null, metadata jsonb default '{}'::jsonb, created_at timestamptz default now());
create table github_repos (id uuid primary key default gen_random_uuid(), provider_credential_id uuid references provider_credentials(id), owner text not null, repo_name text not null, full_name text not null, default_branch text, private boolean default true, connected_at timestamptz default now(), created_at timestamptz default now(), updated_at timestamptz default now());
create table supabase_projects (id uuid primary key default gen_random_uuid(), provider_credential_id uuid references provider_credentials(id), organization_id text, project_ref text not null, project_name text, region text, status text, db_url_encrypted text, connected_at timestamptz default now(), created_at timestamptz default now(), updated_at timestamptz default now());
create table approvals (id uuid primary key default gen_random_uuid(), task_id uuid references ai_tasks(id), approval_type text not null, requested_action text not null, risk_level text not null, status text default 'pending', requested_by uuid, approved_by uuid, rejected_by uuid, reason text, created_at timestamptz default now(), resolved_at timestamptz);
create table audit_logs (id uuid primary key default gen_random_uuid(), actor_type text not null, actor_id uuid, action text not null, target_type text, target_id text, status text not null, metadata jsonb default '{}'::jsonb, created_at timestamptz default now());
create table cost_events (id uuid primary key default gen_random_uuid(), session_id uuid references ai_sessions(id), provider text default 'runpod', resource_type text, gpu_type text, gpu_count int, estimated_hourly_cost numeric, estimated_total_cost numeric, event_type text not null, created_at timestamptz default now());
alter table users_profile enable row level security; alter table provider_credentials enable row level security; alter table ai_sessions enable row level security; alter table model_runtimes enable row level security; alter table ai_tasks enable row level security; alter table ai_task_logs enable row level security; alter table audit_logs enable row level security;
